#!/bin/bash
set -e
echo "Setting up Grailkeeper v1.1..."
mkdir -p grailkeeper/backend grailkeeper/frontend grailkeeper/static
cd grailkeeper

echo "" | base64 -d > Dockerfile
echo "" | base64 -d > backend/app.py
echo "aW1wb3J0IHV2aWNvcm4KaW1wb3J0IHN5cywgb3MKc3lzLnBhdGguaW5zZXJ0KDAsIG9zLnBhdGguZGlybmFtZShfX2ZpbGVfXykpCmlmIF9fbmFtZV9fID09ICJfX21haW5fXyI6CiAgICB1dmljb3JuLnJ1bigiYXBwOmFwcCIsIGhvc3Q9IjAuMC4wLjAiLCBwb3J0PTgwMDAsIHJlbG9hZD1GYWxzZSkK" | base64 -d > backend/entrypoint.py
echo "ZmFzdGFwaT09MC4xMTEuMAp1dmljb3JuPT0wLjI5LjAKcHlkYW50aWM9PTIuNy4xCgpyZXF1ZXN0cz09Mi4zMS4wCg==" | base64 -d > backend/requirements.txt
echo "" | base64 -d > docker-compose.yml
echo "" | base64 -d > frontend/index.html

cat > docker-compose.yml << 'EOF'
services:
  grailkeeper:
    build: .
    container_name: grailkeeper
    ports:
      - "8000:8000"
    volumes:
      - grailkeeper-config:/root/.config/dtctl
    restart: unless-stopped
    mem_limit: 20g

volumes:
  grailkeeper-config:
EOF

echo ""
echo "Grailkeeper v1.1 ready!"
echo "Run: cd grailkeeper && docker compose up --build"
echo "Open: http://localhost:8000"